void BoUpSLP::hoistInsertPoint(ArrayRef<Value *> Operands,
                               BasicBlock *&InsertBlock,
                               Instruction *&InsertInst) {
  for (Value *V : Operands) {
    Instruction *I = dyn_cast<Instruction>(V);
    if (!I)
      continue;

    // If the operand is a PHI node, it is only available in the scope of its
    // parent basic block.
    if (auto *PN = dyn_cast<PHINode>(I)) {
      InsertBlock = DT.findNearestCommonDominator(InsertBlock, PN->getParent());
      continue;
